section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/alert-to-fix-incident-loop.json",
  "title": "Alert-to-Fix Incident Loop",
  "type": "object",
  "required": [
    "artefact_id",
    "incident_id",
    "alert_id",
    "severity",
    "triage",
    "mitigation",
    "root_cause",
    "fix_pr",
    "postmortem_url",
    "alert_quality_patch",
    "evidence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "incident_id": {
      "type": "string",
      "description": "stable identifier (date + slug or pager id)",
      "minLength": 1
    },
    "alert_id": {
      "type": "string",
      "description": "alerting system rule id that fired",
      "minLength": 1
    },
    "severity": {
      "type": "string",
      "description": "sev1|sev2|sev3|sev4",
      "minLength": 1
    },
    "triage": {
      "type": "string",
      "description": "first-cut hypothesis based on observable signals (logs, dashboards)",
      "minLength": 1
    },
    "mitigation": {
      "type": "string",
      "description": "what stopped the bleeding, with timestamp",
      "minLength": 1
    },
    "root_cause": {
      "type": "string",
      "description": "ultimate cause, anchored to a change/event",
      "minLength": 1
    },
    "fix_pr": {
      "type": "string",
      "description": "URL of the merged fix PR",
      "minLength": 1
    },
    "postmortem_url": {
      "type": "string",
      "description": "URL of the postmortem doc",
      "minLength": 1
    },
    "alert_quality_patch": {
      "type": "string",
      "description": "PR/ticket updating the alert rule to reduce future noise",
      "minLength": 1
    }
  },
  "additionalProperties": false
}
